sys_script_include.script:
function CleanupATF(nLimit)
{
	if (IsTestRunning() == true)
	{
		Log('CleanupATF: An ATF test is currently running. The test must be stopped before the full cleanup can take place!');
		return false;
	}

	var nLimit = GetIntegerValue(nLimit);

	Log('CleanupATF: Deleting sys_rollback_context records with type=test_execution...');

	var grRollbackContexts = new GlideRecord('sys_rollback_context');
	grRollbackContexts.addQuery('type','=','test_execution');
	//grRollbackContexts.addQuery('state','=','in_progress');
	if (nLimit > 0)
	{
		grRollbackContexts.setLimit(nLimit);
	}
	grRollbackContexts.query();
	while (grRollbackContexts.next() == true)
	{
		var grRollbackSequence = new GlideRecord('sys_rollback_sequence');
		grRollbackSequence.addQuery('context','=',grRollbackContexts.sys_id);
		grRollbackSequence.query();

		Log('CleanupATF: Deleting: ' + RenderRecordSummary(grRollbackContexts) + ' (' + grRollbackSequence.getRowCount() + ')');

		GlideRecordDeleteMultiple(grRollbackSequence);
		GlideRecordDelete(grRollbackContexts);
	}

	Log('CleanupATF: Deleting sys_atf_test_result records...'); 
	var grTestResults = new GlideRecord('sys_atf_test_result');
	if (nLimit > 0)
	{
		grTestResults.setLimit(nLimit);
	}
	grTestResults.query();
	while (grTestResults.next() == true)
	{
		var grTestStepResults = new GlideRecord('sys_atf_test_result_step');
		grTestStepResults.addQuery('test_result','=',grTestResults.sys_id);
		grTestStepResults.query();

		Log('CleanupATF: Deleting: ' + RenderRecordSummary(grTestResults) + ' (' + grTestStepResults.getRowCount() + ')');

		GlideRecordDeleteMultiple(grTestStepResults);
		GlideRecordDelete(grTestResults);
	}

	Log('CleanupATF: Cleanup has been completed.');
	return true;
}
